mapper.select:
SELECT mc.*, c.coupon_name, c.coupon_type, c.discount_value, c.min_consumption FROM member_coupon mc LEFT JOIN coupon c ON mc.coupon_id = c.id WHERE mc.member_id = #{memberId}
AND mc.use_time IS NOT NULL
AND mc.use_time IS NULL AND mc.expire_time > NOW()
AND mc.use_time IS NULL AND mc.expire_time <= NOW()
AND c.coupon_type = #{couponType}
ORDER BY mc.receive_time DESC
